#!/bin/bash

# Generated by claude.ai

TAG="$1"
REPO="$2"
IS_BETA="${3:-false}"

TAG_NO_V="${TAG#v}"
VERSION="${TAG_NO_V%%-*}"
SUFFIX=$([ "$IS_BETA" = "true" ] && echo "-beta" || echo "")
PREFIX="v${VERSION}${SUFFIX}"

BASE_URL="https://github.com/${REPO}/releases/download/${TAG}"

link() {
  local label="$1"
  local filename="$2"
  printf '<a href="%s/%s"><b><code>%s</code></b></a>' "$BASE_URL" "$filename" "$filename"
}

bullets() {
  printf '<ul style="list-style:none; padding:0; margin:0; text-align:left;">\n'
  for entry in "$@"; do
    IFS='|' read -r label filename <<< "$entry"
    printf '  <li>%s</li>\n' "$(link "$label" "$filename")"
  done
  printf '</ul>'
}

row() {
  local platform="$1"
  shift
  printf '<tr>\n'
  printf '  <td><b>%s</b></td>\n' "$platform"
  printf '  <td>%s</td>\n' "$(bullets "$@")"
  printf '</tr>\n'
}

cat << EOF

---

<div>
<table>
<tr>
  <th>Platform</th>
  <th>Downloads</th>
</tr>
$(row "Android" \
  "arm64-v8a|${PREFIX}-arm64-v8a.apk" \
  "armeabi-v7a|${PREFIX}-armeabi-v7a.apk")
EOF

if [ "$IS_BETA" = "true" ]; then
  row "Android (Clone)" \
    "arm64-v8a|${PREFIX}-clone-arm64-v8a.apk" \
    "armeabi-v7a|${PREFIX}-clone-armeabi-v7a.apk"
fi

row "Windows" \
  "Installer|${PREFIX}-x86_64-Installer.exe"

if [ "$IS_BETA" = "true" ]; then
  row "Linux" \
    ".tar.gz|${PREFIX}.linux.tar.gz" \
    ".deb|${PREFIX}.linux.deb" \
    ".rpm|${PREFIX}.linux.rpm"
  row "Linux (Login)" \
    ".tar.gz|${PREFIX}_login.linux.tar.gz" \
    ".deb|${PREFIX}_login.linux.deb" \
    ".rpm|${PREFIX}_login.linux.rpm"
fi

cat << EOF
</table>
</div>

EOF